                            let recv_desc: &str = if recv_is_byte_arr {
                                "[B"
                            } else if recv_is_int_arr {
                                "[I"
                            } else if recv_is_long_arr {
                                "[J"
                            } else if recv_is_int {
                                "I"
                            } else {
                                "J"
                            };
