    #[test]
    fn typed_lower_binary_param_plus_literal() {
        let module = lower("fun addOne(x: Int): Int = x + 1", "TestKt");
        let f = &module.functions[0];
        let block = &f.blocks[0];
        // 2 stmts: Const(Int(1)) for the literal, BinOp for the add.
        assert_eq!(block.stmts.len(), 2);
        match &block.stmts[0] {
            skotch_mir::Stmt::Assign { dest, value } => {
                assert_eq!(dest.0, 1); // literal goes to slot after param
                assert!(matches!(
                    value,
                    skotch_mir::Rvalue::Const(skotch_mir::MirConst::Int(1))
                ));
            }
        }
        match &block.stmts[1] {
            skotch_mir::Stmt::Assign { dest, value } => {
                assert_eq!(dest.0, 2); // result slot
                match value {
                    skotch_mir::Rvalue::BinOp { op, lhs, rhs } => {
                        assert!(matches!(op, skotch_mir::BinOp::AddI));
                        assert_eq!(lhs.0, 0); // param x
                        assert_eq!(rhs.0, 1); // literal 1
                    }
                    other => panic!("expected BinOp, got {other:?}"),
                }
            }
        }
        assert!(matches!(block.terminator, Terminator::ReturnValue(_)));
    }

    #[test]
    fn typed_lower_when_expression_two_arms() {
        let module = lower(
            "fun name(x: Int): String = when (x) { 1 -> \"one\"; 2 -> \"two\"; else -> \"other\" }",
            "TestKt",
        );
        let f = &module.functions[0];
        // 7 blocks: subj_capture, cmp_1, then_1, cmp_2, then_2, else, join
        assert_eq!(f.blocks.len(), 7);
        // pre block is index 0: capture; Goto(1).
        assert!(matches!(f.blocks[0].terminator, Terminator::Goto(1)));
        // join block is index 6: ReturnValue.
        assert!(matches!(f.blocks[6].terminator, Terminator::ReturnValue(_)));
        // First cmp block branches into then_1 (index 2) or cmp_2 (index 3).
        assert!(matches!(
            f.blocks[1].terminator,
            Terminator::Branch {
                then_block: 2,
                else_block: 3,
                ..
            }
        ));
        // then blocks Goto(6) the join.
        assert!(matches!(f.blocks[2].terminator, Terminator::Goto(6)));
        assert!(matches!(f.blocks[4].terminator, Terminator::Goto(6)));
        // else block (index 5) also Goto(6).
        assert!(matches!(f.blocks[5].terminator, Terminator::Goto(6)));
    }

