    #[test]
    fn typed_lower_nested_class_emits_outer_dollar_inner() {
        let module = lower("class Outer { class Inner }", "TestKt");
        assert!(module.classes.iter().any(|c| c.name == "Outer"));
        assert!(module.classes.iter().any(|c| c.name == "Outer$Inner"));
    }

    #[test]
    fn typed_lower_nested_class_bare_return_type_resolves_to_fq() {
        // `fun makeInner(): Inner = Inner()` inside `class Outer { class
        // Inner ... }` declares the bare simple name `Inner` as its
        // return type. The file-imports map registers `Inner →
        // Outer$Inner` so `makeInner`'s recorded return Ty (used by
        // `class_method_returns` and propagated to call-site result
        // slots) becomes `Ty::Class("Outer$Inner")` rather than the
        // bare `Ty::Class("Inner")`. Without this, the subsequent
        // `n.describe()` invokevirtual emits an owner-class of `Inner`
        // (which doesn't exist at the JVM level) and the call site
        // crashes with NoClassDefFoundError at link time.
        let module = lower(
            "class Outer { class Inner { fun describe(): String = \"hi\" } \
              fun makeInner(): Inner = Inner() }",
            "TestKt",
        );
        let outer = module
            .classes
            .iter()
            .find(|c| c.name == "Outer")
            .expect("Outer");
        let make_inner = outer
            .methods
            .iter()
            .find(|m| m.name == "makeInner")
            .expect("makeInner");
        assert_eq!(make_inner.return_ty, Ty::Class("Outer$Inner".to_string()));
    }

    #[test]
    fn typed_lower_class_with_secondary_ctor_emits_extra_init() {
        let module = lower(
            "class Foo(val x: Int) { constructor(s: String) : this(s.length) {} }",
            "TestKt",
        );
        let foo = module
            .classes
            .iter()
            .find(|c| c.name == "Foo")
            .expect("Foo");
        assert_eq!(foo.secondary_constructors.len(), 1);
        let sc = &foo.secondary_constructors[0];
        assert_eq!(sc.name, "<init>");
        assert_eq!(sc.required_params, 1);
        assert_eq!(sc.param_names, vec!["s".to_string()]);
        // locals: [0] = `this` (Foo), [1] = user param `s` (String),
        // [2] = scratch slot for the `s.length` argument to `this(...)`.
        // The implicit `this` slot at [0] is what gives `emit_user_method`
        // the right offset when it builds the `(Ljava/lang/String;)V`
        // descriptor via `params.iter().skip(1)`. Without it the
        // descriptor came out as `()V`, colliding with the primary
        // `<init>()V` and dropping the typed entry point.
        assert_eq!(
            sc.locals,
            vec![Ty::Class("Foo".to_string()), Ty::String, Ty::Int]
        );
        // params: [this_slot, s_slot] — length 1 + user_param_count.
        assert_eq!(sc.params.len(), 2);
    }

